(() => {
  const isEn = (document.documentElement.lang || '').toLowerCase().startsWith('en');
  const labels = {
    view: isEn ? 'View full diagram' : '查看架构图大图',
    close: isEn ? 'Close' : '关闭',
  };

  let lightbox = null;
  let lightboxImage = null;
  let lastTrigger = null;

  const closeIcon = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" aria-hidden="true"><path d="M6 6l12 12M6 18L18 6"/></svg>`;

  function ensureLightbox() {
    if (lightbox) return;

    lightbox = document.createElement('div');
    lightbox.className = 'diagram-lightbox';
    lightbox.setAttribute('aria-hidden', 'true');
    lightbox.innerHTML = `
      <div class="diagram-lightbox-backdrop" data-diagram-close></div>
      <div class="diagram-lightbox-panel" role="dialog" aria-modal="true" aria-label="${labels.view}">
        <button type="button" class="diagram-lightbox-close" data-diagram-close aria-label="${labels.close}">
          ${closeIcon}
        </button>
        <div class="diagram-lightbox-scroll">
          <img class="diagram-lightbox-image" alt="">
        </div>
      </div>`;

    document.body.appendChild(lightbox);
    lightboxImage = lightbox.querySelector('.diagram-lightbox-image');

    lightbox.addEventListener('click', (event) => {
      if (event.target.closest('[data-diagram-close]')) closeLightbox();
    });
  }

  function openLightbox(trigger, img) {
    ensureLightbox();
    lastTrigger = trigger;
    lightboxImage.src = img.currentSrc || img.src;
    lightboxImage.alt = img.alt;
    lightboxImage.width = img.width || undefined;
    lightboxImage.height = img.height || undefined;
    lightbox.classList.add('open');
    lightbox.setAttribute('aria-hidden', 'false');
    document.body.classList.add('diagram-lightbox-open');
    lightbox.querySelector('.diagram-lightbox-close')?.focus();
  }

  function closeLightbox() {
    if (!lightbox?.classList.contains('open')) return;
    lightbox.classList.remove('open');
    lightbox.setAttribute('aria-hidden', 'true');
    document.body.classList.remove('diagram-lightbox-open');
    lightboxImage.removeAttribute('src');
    lastTrigger?.focus();
    lastTrigger = null;
  }

  function enhanceDiagram(root = document) {
    root.querySelectorAll('.diagram-export').forEach((wrap) => {
      if (wrap.dataset.lightboxReady === 'true') return;

      const img = wrap.querySelector(':scope > img');
      if (!img) return;

      const trigger = document.createElement('button');
      trigger.type = 'button';
      trigger.className = 'diagram-export-trigger';
      trigger.setAttribute('aria-label', `${labels.view}：${img.alt || ''}`.replace(/：$/, ''));

      wrap.insertBefore(trigger, img);
      trigger.appendChild(img);
      wrap.dataset.lightboxReady = 'true';

      trigger.addEventListener('click', () => openLightbox(trigger, img));
    });
  }

  document.addEventListener('keydown', (event) => {
    if (event.key === 'Escape') closeLightbox();
  });

  window.OAIEnhanceDiagramExports = enhanceDiagram;

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => enhanceDiagram());
  } else {
    enhanceDiagram();
  }
})();

